import React from 'react';
import {
  Box,
  Typography,
  Paper,
  Avatar,
  Chip
} from '@mui/material';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import VerifiedIcon from '@mui/icons-material/Verified';

const TestimonialTemplate = ({ 
  type = 'quote', 
  text, 
  clientName, 
  clientTitle, 
  clientImage,
  companyName,
  companyLogo,
  rating = 5,
  verified = true,
  date,
  brandColor = '#5D5FEF'
}) => {

  // Quote Card Template
  if (type === 'quote') {
    return (
      <Box 
        sx={{ 
          p: 4, 
          borderRadius: 3, 
          bgcolor: `${brandColor}10`,
          border: '1px solid',
          borderColor: `${brandColor}30`,
          position: 'relative',
          overflow: 'hidden',
          minHeight: 200,
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          width: '100%'
        }}
      >
        <FormatQuoteIcon 
          sx={{ 
            fontSize: 80, 
            color: brandColor, 
            opacity: 0.2,
            position: 'absolute',
            top: 10,
            left: 10,
            transform: 'rotate(180deg)'
          }} 
        />

        <Typography 
          variant="h6" 
          sx={{ 
            maxWidth: 600, 
            mx: 'auto', 
            fontStyle: 'italic',
            color: 'text.primary',
            fontWeight: 500,
            mb: 3,
            zIndex: 1
          }}
        >
          "{text}"
        </Typography>

        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', mb: 1 }}>
          {clientImage ? (
            <Avatar src={clientImage} alt={clientName} sx={{ mr: 2 }} />
          ) : (
            <Avatar sx={{ mr: 2, bgcolor: brandColor }}>
              {clientName?.charAt(0) || 'C'}
            </Avatar>
          )}
          <Box>
            <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
              {clientName || 'Client Name'}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {clientTitle || 'Position'}{companyName ? `, ${companyName}` : ''}
            </Typography>
          </Box>
        </Box>

        {verified && (
          <Box sx={{ display: 'flex', justifyContent: 'center', mt: 1 }}>
            <Chip 
              icon={<VerifiedIcon fontSize="small" />} 
              label="Verified Testimonial" 
              size="small"
              sx={{ 
                bgcolor: 'success.light', 
                color: 'success.dark',
                '& .MuiChip-icon': { color: 'success.main' }
              }}
            />
          </Box>
        )}

        <Box 
          sx={{ 
            position: 'absolute', 
            bottom: 10, 
            right: 10,
            opacity: 0.5
          }}
        >
          <Typography variant="caption">
            Powered by Testy
          </Typography>
        </Box>
      </Box>
    );
  }

  // Social Post Template
  if (type === 'social') {
    return (
      <Paper 
        elevation={1} 
        sx={{ 
          p: 3, 
          borderRadius: 3,
          overflow: 'hidden',
          width: '100%'
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          {clientImage ? (
            <Avatar src={clientImage} alt={clientName} sx={{ mr: 2, width: 48, height: 48 }} />
          ) : (
            <Avatar sx={{ mr: 2, bgcolor: brandColor, width: 48, height: 48 }}>
              {clientName?.charAt(0) || 'C'}
            </Avatar>
          )}
          <Box>
            <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
              {clientName || 'Client Name'}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {clientTitle || 'Position'}{companyName ? ` at ${companyName}` : ''}
            </Typography>
          </Box>
          {verified && (
            <VerifiedIcon 
              sx={{ 
                ml: 'auto', 
                color: 'success.main',
                fontSize: 20
              }} 
            />
          )}
        </Box>

        <Typography variant="body1" sx={{ mb: 3 }}>
          I wanted to share my experience:
        </Typography>

        <Box 
          sx={{ 
            p: 3, 
            borderRadius: 2, 
            bgcolor: `${brandColor}10`,
            border: '1px solid',
            borderColor: `${brandColor}30`,
            mb: 3
          }}
        >
          <Typography variant="body1" sx={{ fontStyle: 'italic' }}>
            "{text}"
          </Typography>
        </Box>

        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          {date && (
            <Typography variant="caption" color="text.secondary">
              {new Date(date).toLocaleDateString()}
            </Typography>
          )}
          <Typography variant="caption" color="text.secondary">
            Powered by Testy
          </Typography>
        </Box>
      </Paper>
    );
  }

  // Video Script Template
  if (type === 'video') {
    return (
      <Box sx={{ width: '100%' }}>
        <Paper 
          elevation={1} 
          sx={{ 
            p: 3, 
            borderRadius: 3,
            overflow: 'hidden',
            mb: 2
          }}
        >
          <Typography variant="subtitle1" gutterBottom sx={{ fontWeight: 600 }}>
            Video Testimonial Script
          </Typography>

          <Box sx={{ mb: 3 }}>
            <Typography variant="subtitle2" color="text.secondary" gutterBottom>
              INTRO (5-10 seconds)
            </Typography>
            <Typography variant="body2" sx={{ mb: 2, pl: 2 }}>
              "Hi, I'm {clientName || '[Client Name]'}{clientTitle ? `, ${clientTitle}` : ''}{companyName ? ` at ${companyName}` : ''}."
            </Typography>

            <Typography variant="subtitle2" color="text.secondary" gutterBottom>
              TESTIMONIAL (30-45 seconds)
            </Typography>
            <Typography variant="body2" sx={{ mb: 2, pl: 2 }}>
              "{text}"
            </Typography>

            <Typography variant="subtitle2" color="text.secondary" gutterBottom>
              CLOSING (5-10 seconds)
            </Typography>
            <Typography variant="body2" sx={{ pl: 2 }}>
              "I highly recommend their services to anyone looking to achieve similar results."
            </Typography>
          </Box>

          <Box 
            sx={{ 
              p: 2, 
              borderRadius: 2, 
              bgcolor: 'info.light',
              border: '1px solid',
              borderColor: 'info.main',
              mb: 2
            }}
          >
            <Typography variant="caption" color="info.dark">
              <strong>Pro Tip:</strong> Keep the video under 60 seconds for maximum engagement. 
              Look directly at the camera and speak naturally.
            </Typography>
          </Box>
        </Paper>

        <Typography variant="caption" color="text.secondary">
          This script is ready for recording or can be used with our AI video generation feature.
        </Typography>
      </Box>
    );
  }

  // Default fallback
  return (
    <Box sx={{ p: 3, border: '1px dashed grey', borderRadius: 2 }}>
      <Typography>Unknown template type: {type}</Typography>
    </Box>
  );
};

export default TestimonialTemplate;
